class UnionFind:
    def __init__(self, n):
        self.parent = list(range(n))
        self.rank = [0] * n

    def find(self, x):
        # Path Compression
        if self.parent[x] != x:
            self.parent[x] = self.find(self.parent[x])
        return self.parent[x]

    def union(self, x, y):
        # Union by Rank
        root_x, root_y = self.find(x), self.find(y)
        if root_x == root_y:
            return False  # Cycle would form

        if self.rank[root_x] < self.rank[root_y]:
            root_x, root_y = root_y, root_x
        self.parent[root_y] = root_x
        if self.rank[root_x] == self.rank[root_y]:
            self.rank[root_x] += 1
        return True

def kruskal_mst(vertices, edges):
    uf = UnionFind(vertices)
    edges.sort(key=lambda x: x[2])  # Sort by weight
    mst = []
    total_weight = 0

    for u, v, w in edges:
        if uf.union(u, v):
            mst.append((u, v, w))
            total_weight += w
            if len(mst) == vertices - 1:
                break

    return mst, total_weight

#include <stdio.h>
#include <stdlib.h>

typedef struct {
    int u, v, weight;
} Edge;

typedef struct {
    int parent, rank;
} UnionFind;

int find(UnionFind* uf, int x) {
    if (uf[x].parent != x)
        uf[x].parent = find(uf, uf[x].parent);  // Path compression
    return uf[x].parent;
}

void unionSets(UnionFind* uf, int x, int y) {
    int rootX = find(uf, x);
    int rootY = find(uf, y);
    if (rootX == rootY) return;

    // Union by rank
    if (uf[rootX].rank < uf[rootY].rank)
        uf[rootX].parent = rootY;
    else if (uf[rootX].rank > uf[rootY].rank)
        uf[rootY].parent = rootX;
    else {
        uf[rootY].parent = rootX;
        uf[rootX].rank++;
    }
}

int compare(const void* a, const void* b) {
    return ((Edge*)a)->weight - ((Edge*)b)->weight;
}

Edge* kruskalMST(int V, Edge* edges, int E, int* mstSize) {
    UnionFind uf[V];
    for (int i = 0; i < V; i++) {
        uf[i].parent = i;
        uf[i].rank = 0;
    }

    qsort(edges, E, sizeof(Edge), compare);

    Edge* mst = malloc((V - 1) * sizeof(Edge));
    *mstSize = 0;

    for (int i = 0; i < E && *mstSize < V - 1; i++) {
        int uRoot = find(uf, edges[i].u);
        int vRoot = find(uf, edges[i].v);

        if (uRoot != vRoot) {
            mst[*mstSize++] = edges[i];
            unionSets(uf, uRoot, vRoot);
        }
    }
    return mst;
}

import java.util.*;

class Edge implements Comparable<Edge> {
    int u, v, weight;
    Edge(int u, int v, int weight) {
        this.u = u;
        this.v = v;
        this.weight = weight;
    }
    public int compareTo(Edge other) {
        return this.weight - other.weight;
    }
}

class UnionFind {
    int[] parent, rank;
    UnionFind(int n) {
        parent = new int[n];
        rank = new int[n];
        for (int i = 0; i < n; i++) parent[i] = i;
    }
    int find(int x) {
        if (parent[x] != x) 
            parent[x] = find(parent[x]);  // Path compression
        return parent[x];
    }
    boolean union(int x, int y) {
        int rootX = find(x);
        int rootY = find(y);
        if (rootX == rootY) return false;

        // Union by rank
        if (rank[rootX] < rank[rootY]) parent[rootX] = rootY;
        else if (rank[rootX] > rank[rootY]) parent[rootY] = rootX;
        else { parent[rootY] = rootX; rank[rootX]++; }
        return true;
    }
}

public class KruskalMST {
    public static List<Edge> kruskal(int vertices, List<Edge> edges) {
        Collections.sort(edges);
        UnionFind uf = new UnionFind(vertices);
        List<Edge> mst = new ArrayList<>();

        for (Edge e : edges) {
            if (uf.union(e.u, e.v)) {
                mst.add(e);
                if (mst.size() == vertices - 1) break;
            }
        }
        return mst;
    }

    public static void main(String[] args) {
        int V = 5;
        List<Edge> edges = Arrays.asList(
            new Edge(0, 1, 1), new Edge(1, 2, 2),
            new Edge(0, 2, 3), new Edge(0, 3, 4),
            new Edge(1, 3, 5), new Edge(2, 3, 6),
            new Edge(3, 4, 7), new Edge(2, 4, 8)
        );
        List<Edge> mst = kruskal(V, edges);
        int total = mst.stream().mapToInt(e -> e.weight).sum();
        System.out.println("MST Weight: " + total);
    }
}
